INSERT INTO `products` VALUES (1,1,'Producto demo','producto-demo-1772237672','este es un producto demo',10.00,8.00,NULL,'https://i.ibb.co/Ld1My3j3/8e783531ff76.jpg',0,'inactive','2026-02-28 00:14:32',1,1,'storage/digital/digital_1_1772257371.zip'),(2,8,'Decoración para boda','decoraci-n-para-boda-1772257369','Vector descargable para reproducir el diseño de un artículo decorativo para boda.\r\nUtiliza tu máquina de corte CNC para la realización de este proyecto.',10.00,0.00,NULL,'https://i.ibb.co/ymPdCt6t/d1d2bf6d7dd6.png',1,'active','2026-02-28 05:42:49',0,0,'storage/digital/digital_2_1772262842.zip'),(3,4,'Taza Cerámica Personalizada Premium dd','taza-ceramica-personalizada-premium','Taza de cerámica de alta calidad con recubrimiento especial para sublimación full color. Ideal para regalos corporativos y personales.',8.50,7.65,5.00,'https://originaliasalamanca.es/wp-content/uploads/2018/11/taza-personalizada-ceramica.webp',0,'active','2026-02-28 09:13:02',0,0,NULL),(4,4,'Taza Mágica Sensible al Calor','taza-magica-sensible-al-calor','Taza que revela tu diseño personalizado al contacto con bebidas calientes. Efecto sorprendente y divertido.',12.00,10.80,NULL,'https://i5.walmartimages.com/asr/665070ed-08f4-4702-b2c5-3de9a2901564.e63a0da89f854e4956ef3234486eb719.jpeg?odnHeight=612&odnWidth=612&odnBg=FFFFFF',0,'active','2026-02-28 09:13:02',0,0,NULL),(5,4,'Set de Tazas para Parejas','set-de-tazas-para-parejas','Par de tazas con diseños complementarios personalizados. El regalo perfecto para aniversarios y San Valentín.',15.00,13.50,NULL,'https://http2.mlstatic.com/D_Q_NP_990938-MLU74316258326_022024-O.webp',0,'active','2026-02-28 09:13:02',0,0,NULL),(6,4,'Taza de Acero Inoxidable para Camping','taza-de-acero-inoxidable-para-camping','Taza resistente y ligera, personalizada con grabado láser. Ideal para aventureros y actividades al aire libre.',14.50,13.05,NULL,'https://www.epilicitanas.com/wp-content/uploads/2023/05/shirley-negro-laser-1.png',0,'active','2026-02-28 09:13:02',0,0,NULL),(7,2,'Llavero de Cuero Grabado a Láser','llavero-de-cuero-grabado-a-laser','Elegante llavero de cuero legítimo con grabado de precisión. Personaliza con nombres, fechas o logotipos.',5.00,4.50,NULL,'https://http2.mlstatic.com/D_NQ_NP_988000-MLA51813934026_102022-O.webp',0,'active','2026-02-28 09:13:02',0,0,NULL),(8,2,'Llavero Metálico Giratorio Premium','llavero-metalico-giratorio-premium','Llavero de metal con pieza central giratoria personalizable por ambas caras. Duradero y brillante.',6.50,5.85,NULL,'https://m.media-amazon.com/images/I/71DQtjbZv7L._AC_UY350_.jpg',0,'active','2026-02-28 09:13:02',0,0,NULL),(9,2,'Llavero de Madera de Roble Artesanal','llavero-de-madera-de-roble-artesanal','Llavero cortado y grabado en madera de roble natural. Tacto cálido y diseño ecológico único.',4.00,3.60,NULL,'https://i.etsystatic.com/20374417/r/il/4987d6/2609223950/il_570xN.2609223950_9lrn.jpg',0,'active','2026-02-28 09:13:02',0,0,NULL),(10,2,'Llavero de Acrílico Espejado Personalizado','llavero-de-acrilico-espejado-personalizado','Llavero con efecto espejo en color plata u oro. Corte láser de formas personalizadas de alta visibilidad.',3.50,3.15,NULL,'https://www.promostore.ec/wp-content/uploads/2019/09/Llavero-acrilico-personalizado-1-800x800.webp',0,'active','2026-02-28 09:13:02',0,0,NULL),(11,5,'Cuadro Decorativo en Relieve de Madera','cuadro-decorativo-en-relieve-de-madera','Arte de pared con múltiples capas de madera cortadas a láser. Diseño tridimensional impresionante.',45.00,40.50,NULL,'https://artemaxico.com.mx/cdn/shop/products/mad2.png?v=1634852147',0,'active','2026-02-28 09:13:02',0,0,NULL),(12,5,'Posavasos de Bambú con Diseños Mandalas','posavasos-de-bambu-con-disenos-mandalas','Set de 4 posavasos de bambú grabado con patrones geométricos complejos. Funcionales y decorativos.',18.00,16.20,NULL,'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ7ySEDQm1s9PVnEf3DeznXD_kHwPh8GKU8Eg&s',0,'active','2026-02-28 09:13:02',0,0,NULL),(13,5,'Lámpara LED con Panel de Acrílico Grabado','lampara-led-con-panel-de-acrilico-grabado','Base táctil con cambio de colores e ilustración grabada en acrílico transparente. Ideal como luz de noche.',25.00,22.50,NULL,'https://tiendavacards.com/cdn/shop/files/IMG_4959.jpg?v=1736390306&width=1445',0,'active','2026-02-28 09:13:02',0,0,NULL),(14,5,'Tabla de Cortar Nut para Cocina','tabla-de-cortar-nut-para-cocina','Tabla de madera maciza grabada con recetas o mensajes personalizados. Un detalle único para el hogar.',35.00,31.50,NULL,'https://http2.mlstatic.com/D_NQ_NP_805551-MLU74861235531_032024-O.webp',0,'active','2026-02-28 09:13:02',0,0,NULL),(15,5,'Vinilo Adhesivo Decorativo de Pared','vinilo-adhesivo-decorativo-de-pared','Frases y diseños en vinilo de corte de alta calidad. Fácil aplicación y gran durabilidad.',12.50,11.25,NULL,'https://content.click2printsolutions.com/thumb/VINILOS-PAREDES-835X380-dd571.jpg',0,'active','2026-02-28 09:13:02',0,0,NULL),(16,5,'Stickers Holográficos Troquelados (Set)','stickers-holograficos-troquelados-set','Pack de pegatinas con efecto holográfico y corte de forma personalizado. Resistentes al agua.',7.00,6.30,NULL,'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTvhz4F32ryGEGHUphecpypFhnwvPmUcSr3Ew&s',0,'inactive','2026-02-28 09:13:02',0,0,NULL),(17,5,'Cinta Identificadora con Vinilo Téxtil','cinta-identificadora-con-vinilo-textil','Cintas de tela personalizada con vinilo térmico. Ideal para uniformes y eventos.',2.50,2.25,NULL,'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ4HIG00n7zMcu7_61UWff1nCD1XHeBrw8rWA&s',0,'active','2026-02-28 09:13:02',0,0,NULL);
