p',1,0,'2026-02-28 09:41:40'),(23,17,'url','https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ4HIG00n7zMcu7_61UWff1nCD1XHeBrw8rWA&s',1,0,'2026-02-28 09:43:39'),(26,15,'url','https://content.click2printsolutions.com/thumb/VINILOS-PAREDES-835X380-dd571.jpg',0,1,'2026-02-28 20:41:29');
