/*!40000 ALTER TABLE `portfolio` DISABLE KEYS */;
INSERT INTO `portfolio` VALUES (1,'Grabado Láser de Precisión en Vasos Térmicos','grabado-l-ser-de-precisi-n-en-vasos-t-rmicos','Personalización de alta durabilidad para marcas corporativas y regalos exclusivos.','<h2>Detalles del Proyecto</h2><p>Realizamos un grabado láser de fibra sobre acero inoxidable con recubrimiento de pintura electrostática. El resultado es un acabado plateado brillante que no se borra con el tiempo ni el uso.</p><ul><li><strong>Material:</strong> Acero Inoxidable</li><li><strong>Técnica:</strong> Grabado de Fibra Óptica</li><li><strong>Tiempo de ejecución:</strong> 15 minutos por pieza</li></ul><blockquote>\"La calidad del grabado superó nuestras expectativas para el evento corporativo.\" - Cliente Satisfecho</blockquote>','https://images.unsplash.com/photo-1517254456976-ee8682099819?auto=format&fit=crop&q=80&w=800','Grabado Láser','Descubre cómo personalizamos vasos térmicos con grabado láser de alta precisión para empresas.','Láser, Acero, Corporativo','2026-02-15','2026-02-28 07:45:14'),(2,'Letreros Luminosos en Acrílico para Recepción','letreros-luminosos-en-acr-lico-para-recepci-n','Elegancia y visibilidad para la identidad visual de tu oficina o local comercial.','<h2>Impacto Visual</h2><p>Combinamos el corte láser de precisión con iluminación LED blanca cálida. El acrílico cristal de 5mm permite una difusión de luz perfecta en los bordes pulidos.</p><p>Este tipo de trabajos requiere un diseño vectorial impecable para asegurar que el encaje sea milimétrico.</p><ul><li><strong>Material:</strong> Acrílico 5mm + Base de Madera</li><li><strong>Iluminación:</strong> LED 12v</li><li><strong>Uso:</strong> Interior</li></ul>','https://images.unsplash.com/photo-1563013544-824ae1b704d3?auto=format&fit=crop&q=80&w=800','Corte Láser','Letreros de acrílico cortados a láser con iluminación LED para negocios y oficinas.','Acrílico, LED, Publicidad','2026-02-20','2026-02-28 07:45:14'),(3,'Sublimación Full Color en Camisetas Técnicas','sublimaci-n-full-color-en-camisetas-t-cnicas','Impresión vibrante que penetra las fibras, ideal para uniformes deportivos de alto rendimiento.','<h2>Colores Infinitos</h2><p>La sublimación nos permite transferir diseños complejos con miles de colores sin tacto sobre la prenda. La durabilidad es total: el diseño no se cuartea ni pierde color con los lavados.</p><ul><li><strong>Tela:</strong> Poliéster Dry-Fit</li><li><strong>Tamaño:</strong> A3 (Máximo detalle)</li><li><strong>Cantidad:</strong> Pedidos desde 12 unidades</li></ul>','https://images.unsplash.com/photo-1521572267360-ee0c2909d518?auto=format&fit=crop&q=80&w=800','Sublimación','Servicio de sublimación de alta calidad para ropa deportiva y eventos.','Sublimación, Textil, Deporte','2026-02-25','2026-02-28 07:45:14'),(4,'Vectores Digitales para Corte y Grabado','vectores-digitales-para-corte-y-grabado','Diseños listos para usar en máquinas CNC y Láser. Ahorra tiempo en tus diseños.','<h2>Pack de Vectores</h2><p>Ofrecemos archivos optimizados en formatos DXF, SVG y AI. Cada trazo está verificado para evitar saltos del cabezal láser y asegurar un corte limpio.</p><ul><li><strong>Formato:</strong> SVG, DXF, AI</li><li><strong>Estilo:</strong> Geométrico / Floral</li><li><strong>Compatibilidad:</strong> RDWorks, LightBurn, CorelDRAW</li></ul>','https://images.unsplash.com/photo-1581091226825-a6a2a5aee158?auto=format&fit=crop&q=80&w=800','Otro','Descarga diseños vectoriales optimizados para tus proyectos de corte láser.','Diseño, Vectores, CNC','2026-02-27','2026-02-28 07:45:14'),(5,'Medallas de Madera para Competencias Escolares','medallas-de-madera-para-competencias-escolares','Una alternativa ecológica y económica para premiaciones y eventos masivos.','<h2>Sustentabilidad</h2><p>Utilizamos MDF de 3mm con acabado natural o barnizado. El grabado láser permite incluir el logo del evento y el nombre de la competencia con gran detalle.</p><ul><li><strong>Material:</strong> MDF 3mm</li><li><strong>Acabado:</strong> Lazo de colores incluido</li><li><strong>Ventaja:</strong> Proceso rápido y económico</li></ul>','https://images.unsplash.com/photo-1589487391730-58f20eb2c308?auto=format&fit=crop&q=80&w=800','Grabado Láser','Medallas de madera personalizadas con grabado láser para eventos y deportes.','Madera, Medallas, Eventos','2026-02-28','2026-02-28 07:45:14'),(6,'Trofeos de Acrílico para Torneo de Golf','trofeos-de-acr-lico-para-torneo-de-golf','Diseño vanguardista con grabado profundo y base de madera noble.','<h2>Excelencia Deportiva</h2><p>Fabricamos trofeos personalizados utilizando acrílico de 10mm de espesor, cortado con láser para lograr bordes con acabado de diamante.</p><ul><li><strong>Material:</strong> Acrílico Cristal 10mm</li><li><strong>Base:</strong> Roble Americano</li><li><strong>Técnica:</strong> Grabado láser invertido</li></ul>','https://i00.eu/img/811/550x550f/59mioa6f/2353.webp','Corte Láser','Trofeos de acrílico premium personalizados para eventos deportivos de alto nivel.','Trofeos, Acrílico, Eventos','2026-02-28','2026-02-28 08:03:34'),(7,'Señalética de Madera para Hotel Boutique','se-al-tica-de-madera-para-hotel-boutique','Integración armoniosa con el entorno natural mediante el uso de maderas recuperadas.','<h2>Navegación Intuitiva</h2><p>Desarrollamos toda la señalética interna y externa para \"El Descanso\", utilizando madera de teca grabada con láser de CO2 para resistir la humedad.</p><ul><li><strong>Estilo:</strong> Rústico Moderno</li><li><strong>Durabilidad:</strong> Alta (Protección UV)</li><li><strong>Técnica:</strong> Grabado profundo</li></ul>','https://images.unsplash.com/photo-1563245372-f21724e3856d?auto=format&fit=crop&q=80&w=800','Grabado Láser','Señalética elegante en madera para hoteles y espacios comerciales.','Hotelería, Madera, Señalética','2026-02-27','2026-02-28 08:03:34'),(8,'Personalización de Agendas en Cuero Sintético','personalizaci-n-de-agendas-en-cuero-sint-tico','Grabado sutil y elegante para merchandising corporativo de fin de año.','<h2>Identidad Corporativa</h2><p>Grabamos más de 500 agendas para el grupo financiero XYZ, logrando un contraste perfecto en el material sintético bitono.</p><ul><li><strong>Material:</strong> PU Leather</li><li><strong>Resultado:</strong> Cambio de color por calor</li><li><strong>Precisión:</strong> Logos de hasta 2mm de detalle</li></ul>','https://maxred.ec/wp-content/uploads/2025/01/Agenda-naturaleza-y-cultura.jpg','Grabado Láser','Agendas corporativas personalizadas con grabado láser en cuero y sintéticos.','Corporativo, Cuero, Oficina','2026-02-26','2026-02-28 08:03:34'),(9,'Cajas de Madera para Vinos Premium','cajas-de-madera-para-vinos-premium','Empaque de lujo con cierre magnético y grabado personalizado en la tapa.','<h2>Presentación de Lujo</h2><p>Diseñamos este empaque especial para ediciones limitadas de Malbec, incorporando un sistema de encastres ocultos realizado 100% en corte láser.</p><ul><li><strong>Madera:</strong> Pino seleccionado</li><li><strong>Cierre:</strong> Imanes de neodimio</li><li><strong>Acabado:</strong> Barniz mate</li></ul>','https://images.unsplash.com/photo-1510812431401-41d2bd2722f3?auto=format&fit=crop&q=80&w=800','Corte Láser','Empaques de lujo en madera para vinos con grabado láser personalizado.','Packaging, Vino, Regalos','2026-02-25','2026-02-28 08:03:34'),(10,'Llaveros de Acrílico Espejado para Marcas de Moda','llaveros-de-acr-lico-espejado-para-marcas-de-moda','Accesorios vibrantes y modernos que capturan la luz y la atención.','<h2>Brillo y Estilo</h2><p>Producción masiva de llaveros en acrílico espejo oro y plata para lanzamiento de nueva colección.</p><ul><li><strong>Efecto:</strong> Espejo alta reflexión</li><li><strong>Formas:</strong> Irregulares personalizadas</li><li><strong>Técnica:</strong> Corte y grabado superficial</li></ul>','https://images.unsplash.com/photo-1582142839970-2b9e04b60f65?auto=format&fit=crop&q=80&w=800','Corte Láser','Llaveros de acrílico espejo personalizados para marcas y promociones.','Moda, Acrílico, Accesorios','2026-02-24','2026-02-28 08:03:34');
